module RefModule(input rst,input clk,input sig,output rise,output fall);reg [1:0] obf_sig_reg; 
 always @(posedge clk or posedge rst) 
  if (rst == 1'b1) 
  obf_sig_reg <= 2'b00; 
  else 
  obf_sig_reg <= {obf_sig_reg[0], sig}; 
 assign rise = obf_sig_reg[0] == 1'b1 && obf_sig_reg[1] == 1'b0 ? 1'b1 : 1'b0; 
 assign fall = obf_sig_reg[0] == 1'b0 && obf_sig_reg[1] == 1'b1 ? 1'b1 : 1'b0; 
 endmodule
